        [9] = "Упознајте %s, инвентивног банкарског виртуоза, са само %s година, који већ стоји међу врхунским пореским стручњацима државе %s---%s. Са визионарским размишљањем и непоколебљивом етиком, он настоји да револуционише банкарску индустрију, трасирајући пут ка трајној финансијској сигурности својих клијената.",
        [10] = "Прихватите сјај %s, банкарског генија, старог %s година, који се истиче као један од најсјајнијих пореских стручњака у живахној држави %s---%s. Са визионарским циљевима и непоколебљивим принципима, он настоји да преобликује банкарске праксе, водећи клијенте ка будућности финансијског обиља.",
        [11] = "Представљамо %s, иновативног финансијског експерта, старог %s година, који већ стоји међу елитним банкарским саветницима у држави %s---%s. Вођен визионарским духом и непоколебљивим интегритетом, он тежи да трансформише банкарски пејзаж, осигуравајући да просперитет клијената не познаје границе.",
        [12] = "Упознајте %s, финансијског лидера визионара, старог %s година, који се уздиже међу главним банкарским саветницима државе %s---%s. Вођен непоколебљивим принципима, он тежи да трансформише банкарску индустрију, остављајући дубок утицај на будућност финансија клијената.",
        [13] = "Уђите у свет %s, продорног финансијског стратега, старог %s година, препознатог као један од водећих визионарских инвеститора у живахној држави %s---%s. Са визионарским циљевима и непоколебљивом посвећеношћу етици, он настоји да редефинише банкарске праксе и оснажи клијенте ка финансијском успеху.",
        [14] = "Откријте %s, младог и бриљантног финансијског саветника, старог %s година, који изазива таласе у космополитској држави %s---%s. Са иновативним размишљањем и непоколебљивим интегритетом, он настоји да преобликује банкарски пејзаж, отварајући пут ка трајној финансијској просперитету клијената.",
        [15] = "Придружите се %s, изузетном банкарском таленту, са само %s година, који се успиње као један од главних визионарских инвеститора у држави %s---%s. Вођен визионарским приступом и непоколебљивом етиком, он настоји да обнови банкарске праксе, водећи клијенте ка сигурној и растућој финансијској будућности.",
        [16] = "Уђите у царство %s, проницљивог финансијског генија, старог %s година, који оставља траг као један од водећих банкарских саветника државе %s---%s. Са визионарским размишљањем и непоколебљивим принципима, он тежи да трансформише банкарску индустрију, осигуравајући трајан утицај на финансијска достигнућа клијената.",
        [17] = "Добродошли у свет %s, инвентивног финансијског експерта, старог %s година, који се већ истиче међу главним банкарским саветницима државе %s---%s. Вођен визионарским духом и непоколебљивом етиком, он тежи да преобликује банкарски пејзаж, трасирајући пут ка континуираном финансијском расту клијената.",
        [18] = "Упознајте %s, иновативног банкарског генија, старог %s година, који се истиче као један од најбољих визионарских инвеститора у живахној држави %s---%s. Са визионарским приступом и непоколебљивом интегритетом, он тежи да редефинише банкарске праксе, осигуравајући да се финансијски снови клијената остваре.",
        [19] = "Прихватите сјај %s, цењеног банкарског генија, старог %s година, који се истиче као један од најсјајнијих визионарских инвеститора у динамичној држави %s---%s. Вођен визионарским циљевима и непоколебљивим принципима, он настоји да преобликује банкарске праксе, водећи клијенте ка будућности финансијског обиља.",
        [20] = "Представљамо %s, банкарског маестра, са само %s година, већ признатог међу елитним финансијским саветницима државе %s---%s. Са визионарским размишљањем и непоколебљивом етиком, он тежи да трансформише банкарску индустрију, обезбеђујући клијентима просперитетан и трајан финансијски пут.",
    },

    ["age"] = { -- Сакривени промптови за године (Прво %s: Име / Друго %s: Место пребивалишта / *: Године)
